tool_calls:
awk -F= '
FNR==NR {a[$1]=$2; next}
{b[$1]=$2}
END {
  print "Configuration comparison summary:";
  print "";

  # Added keys
  added_count=0;
  for (k in b) if (!(k in a)) {added[++added_count]=k}
  if (added_count==0) {
    print "Added keys: none";
  } else {
    print "Added keys:";
    n=asorti(added, idx);
    for (i=1; i<=n; i++) {
      key=added[idx[i]];
      printf "  - %s=%s\n", key, b[key];
    }
  }
  print "";

  # Removed keys
  removed_count=0;
  for (k in a) if (!(k in b)) {removed[++removed_count]=k}
  if (removed_count==0) {
    print "Removed keys: none";
  } else {
    print "Removed keys:";
    n=asorti(removed, idx2);
    for (i=1; i<=n; i++) {
      key=removed[idx2[i]];
      printf "  - %s (was %s)\n", key, a[key];
    }
  }
  print "";

  # Changed keys
  changed_count=0;
  for (k in a) if ((k in b) && a[k] != b[k]) {changed[++changed_count]=k}
  if (changed_count==0) {
    print "Changed keys: none";
  } else {
    print "Changed keys:";
    n=asorti(changed, idx3);
    for (i=1; i<=n; i++) {
      key=changed[idx3[i]];
      printf "  - %s: %s -> %s\n", key, a[key], b[key];
    }
  }
}
' /data/v1.conf /data/v2.conf

